mapper.select:
SELECT DATE(collect_time) AS period, SUM(energy) AS totalEnergy, AVG(power) AS avgPower, MAX(power) AS maxPower, MIN(power) AS minPower FROM power_data WHERE collect_time BETWEEN #{startTime} AND #{endTime}
AND device_id = #{deviceId}
GROUP BY DATE(collect_time) ORDER BY period

SELECT SUBSTRING(CAST(collect_time AS VARCHAR), 1, 7) AS period, SUM(energy) AS totalEnergy, AVG(power) AS avgPower, MAX(power) AS maxPower, MIN(power) AS minPower FROM power_data WHERE collect_time BETWEEN #{startTime} AND #{endTime}
AND device_id = #{deviceId}
GROUP BY SUBSTRING(CAST(collect_time AS VARCHAR), 1, 7) ORDER BY period

SELECT HOUR(collect_time) AS hourIndex, AVG(power) AS avgPower, MAX(power) AS maxPower, MIN(power) AS minPower FROM power_data WHERE DATE(collect_time) = DATE(#{date})
AND device_id = #{deviceId}
GROUP BY HOUR(collect_time) ORDER BY hourIndex
